{"path": "/tmp/sv-105cbd5a23f346bcb091c98dbb2ca84f/Components/Board/BoardColumn.razor", "file_text": "<div class="board-column">
    <div class="column-header">
        <h3>@Title</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, LeftStatus!))"
                      OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, RightStatus!))" />
        }
        <AddTaskForm OnSave="HandleAddTask" />
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string Title { get; set; } = "";

    [Parameter, EditorRequired]
    public string Status { get; set; } = "";

    [Parameter]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public string? LeftStatus { get; set; }

    [Parameter]
    public string? RightStatus { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }

    [Parameter]
    public EventCallback<(string Status, AddTaskForm.AddTaskRequest Request)> OnAddTask { get; set; }

    private bool ShowMoveLeft => LeftStatus is not null;
    private bool ShowMoveRight => RightStatus is not null;

    private async Task HandleAddTask(AddTaskForm.AddTaskRequest request)
    {
        await OnAddTask.InvokeAsync((Status, request));
    }
}
"}

