+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+@if (isLoading)
+{
+    <p class="board-loading">Loading tasks…</p>
+}
+else if (errorMessage is not null)
+{
+    <div class="board-error">
+        <p>@errorMessage</p>
+        <button @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStats TotalCount="allTasks.Count"
+                TodoCount="tasksByStatus[Todo].Count"
+                InProgressCount="tasksByStatus[InProgress].Count"
+                DoneCount="tasksByStatus[Done].Count"
+                OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />
+
+    <BoardSearchBar @bind-SearchTerm="searchTerm" />
+
+    <div class="board-columns">
+        <BoardColumn Title="To Do" Status="@Todo"
+                     Tasks="Filter(tasksByStatus[Todo])"
+                     RightStatus="@InProgress"
+                     OnMoveTask="HandleMoveTask"
+                     OnAddTask="HandleAddTask" />
+
+        <BoardColumn Title="In Progress" Status="@InProgress"
+                     Tasks="Filter(tasksByStatus[InProgress])"
+                     LeftStatus="@Todo" RightStatus="@Done"
+                     OnMoveTask="HandleMoveTask"
+                     OnAddTask="HandleAddTask" />
+
+        <BoardColumn Title="Done" Status="@Done"
+                     Tasks="Filter(tasksByStatus[Done])"
+                     LeftStatus="@InProgress"
+                     OnMoveTask="HandleMoveTask"
+                     OnAddTask="HandleAddTask" />
+    </div>
+}
+
+@code {
+    private const string Todo = "To Do";
+    private const string InProgress = "In Progress";
+    private const string Done = "Done";
+    private static readonly string[] Statuses = [Todo, InProgress, Done];
+
+    private List<TaskItem> allTasks = new();
+    private Dictionary<string, List<TaskItem>> tasksByStatus = new();
+    private string searchTerm = "";
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        isLoading = true;
+        errorMessage = null;
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+            RebuildGroups();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to load tasks: {ex.Message}";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void RebuildGroups()
+    {
+        tasksByStatus = Statuses.ToDictionary(
+            s => s,
+            s => allTasks.Where(t => t.Status == s).ToList());
+    }
+
+    private List<TaskItem> Filter(List<TaskItem> tasks)
+    {
+        if (string.IsNullOrWhiteSpace(searchTerm))
+            return tasks;
+
+        return tasks
+            .Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
+            .ToList();
+    }
+
+    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
+            var task = allTasks.First(t => t.Id == args.TaskId);
+            var updated = task with { Status = args.NewStatus };
+            allTasks = allTasks.Select(t => t.Id == args.TaskId ? updated : t).ToList();
+            RebuildGroups();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to move task: {ex.Message}";
+        }
+    }
+
+    private async Task HandleAddTask((string Status, AddTaskForm.AddTaskRequest Request) args)
+    {
+        try
+        {
+            var newTask = await TaskService.CreateTaskAsync(
+                args.Request.Title, args.Request.Assignee,
+                args.Request.Priority, args.Request.DueDate);
+            allTasks.Add(newTask with { Status = args.Status });
+            RebuildGroups();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Failed to create task: {ex.Message}";
+        }
+    }
+}
+

